CREATE TYPE orders_return_case_status AS ENUM ('requested', 'authorized', 'refused', 'awaiting_receipt', 'closed');
CREATE TABLE public.orders_return_cases (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), client_id uuid NOT NULL REFERENCES public.clients(id) ON DELETE CASCADE, sale_id uuid NOT NULL REFERENCES public.sales(id) ON DELETE CASCADE, status orders_return_case_status NOT NULL DEFAULT 'requested', request_reason text, requested_by uuid REFERENCES public.user_nodes(id) ON DELETE SET NULL, authorized_by uuid REFERENCES public.user_nodes(id) ON DELETE SET NULL, authorized_at timestamptz, refused_by uuid REFERENCES public.user_nodes(id) ON DELETE SET NULL, refused_at timestamptz, refusal_reason text, idempotency_key text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT orders_return_cases_client_idempotency_uniq UNIQUE (client_id, idempotency_key));
CREATE TABLE public.orders_return_case_lines (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), return_case_id uuid NOT NULL REFERENCES public.orders_return_cases(id) ON DELETE CASCADE, sale_line_id uuid NOT NULL REFERENCES public.sale_lines(id) ON DELETE RESTRICT, qty int NOT NULL CHECK (qty > 0), reason text, inventory_return_id uuid REFERENCES public.inventory_returns(id) ON DELETE RESTRICT, refund_id uuid REFERENCES public.orders_refunds(id) ON DELETE RESTRICT, created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT orders_return_case_lines_case_line_uniq UNIQUE (return_case_id, sale_line_id), CONSTRAINT orders_return_case_lines_inventory_return_uniq UNIQUE (inventory_return_id), CONSTRAINT orders_return_case_lines_refund_uniq UNIQUE (refund_id));
CREATE INDEX orders_return_cases_client_status_idx ON public.orders_return_cases (client_id, status, created_at DESC);
CREATE INDEX orders_return_case_lines_sale_line_idx ON public.orders_return_case_lines (sale_line_id);
CREATE TRIGGER orders_return_cases_updated_at BEFORE UPDATE ON public.orders_return_cases FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();
